import type { Locale } from '@meli/i18n';
import type { RequestHandler } from 'express';

import * as iv from '@meli/input-validation';
import { resolveAcceptLanguage } from 'resolve-accept-language';
import { getCountriesData } from 'frontend-country_config';

const LOCALES = Object.values(getCountriesData()).map(({ locale }) =>
  locale.replace('_', '-'),
) as [Locale, ...Array<Locale>]; // LOCALES always has values, so we can assert it as a non-empty array

function getLocaleFromAcceptLanguage(req: Parameters<RequestHandler>[0]) {
  const cookies = req.cookies as Record<string, string>;
  const acceptLang = cookies.locale || req.header('accept-language');

  return acceptLang && resolveAcceptLanguage(acceptLang, LOCALES, 'es-AR');
}

export const i18nIVMiddleware: RequestHandler = iv.createValidationMiddleware({
  schema: { query: iv.object({ locale: iv.enumeration(LOCALES).optional() }) },
});

export const i18nLocaleMiddleware: RequestHandler = (req, res, next) => {
  const locale =
    req.locale || req.query.locale || getLocaleFromAcceptLanguage(req);

  if (locale) {
    req.locale = locale as Locale;
  }

  return next();
};
